import React from 'react';
import { AbsoluteFill, useCurrentFrame } from 'remotion';
import { GridField, Glow } from '../../../lib/primitives';
import { dynamicGridSchema, type DynamicGridProps } from './schema';

export { dynamicGridSchema, type DynamicGridProps };

/**
 * A technical grid that drifts diagonally — the `GridField` primitive on a
 * frame-driven translate that loops by one cell, so it's seamless and
 * deterministic. Optional centered accent `Glow` lifts the middle. A
 * full-canvas atmosphere layer for dashboards / data / dev scenes.
 *
 * @example
 * <DynamicGrid variant="dots" />
 */
export const DynamicGrid: React.FC<DynamicGridProps> = ({
  cell, variant, color, speed, opacity, glow, glowColor, background,
}) => {
  const frame = useCurrentFrame();
  const offset = (frame * speed) % cell;

  return (
    <AbsoluteFill style={{ background, overflow: 'hidden' }}>
      <div style={{ position: 'absolute', inset: `-${cell}px`, transform: `translate(${-offset}px, ${-offset}px)` }}>
        <GridField cell={cell} variant={variant} color={color} opacity={opacity} />
      </div>
      {glow && <Glow color={glowColor} size={1} opacity={0.22} />}
    </AbsoluteFill>
  );
};

import { z } from 'zod';

/** Zod schema for {@link DynamicGrid} props. */
export const dynamicGridSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted. */
  kind: z.literal('dynamic-grid').default('dynamic-grid'),
  /** Cell size in px. */
  cell: z.number().int().min(4).default(48),
  /** Ruled lines or a dot lattice. */
  variant: z.enum(['lines', 'dots']).default('lines'),
  /** Grid color. Defaults to `--onda-border`. */
  color: z.string().default('var(--onda-border, #1C1C22)'),
  /** Scroll speed in px/frame (diagonal drift). */
  speed: z.number().default(0.4),
  /** Grid opacity. */
  opacity: z.number().min(0).max(1).default(0.6),
  /** Add a centered accent glow over the grid. */
  glow: z.boolean().default(true),
  /** Glow color. Defaults to `--onda-accent`. */
  glowColor: z.string().default('var(--onda-accent, #D96B82)'),
  /** Canvas color behind the grid. */
  background: z.string().default('var(--onda-bg, #08080A)'),
});

/** Inferred props for {@link DynamicGrid}. */
export type DynamicGridProps = z.infer<typeof dynamicGridSchema>;
